"""
Parameterized generator for GH345_hrm_3712.

Source PR:    https://github.com/arii/hrm/pull/3712
Source Issue: https://github.com/arii/hrm/issues/3659

Seed varies: renames 'accumulate' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH345_hrm_3712'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH345_hrm_3712'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('accumulate', 'accumulate' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH345_hrm_3712',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'arii/hrm',
                "pr_number": 3712,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/arii/hrm/pull/3712",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'lib/utils.ts': "/**\n * @fileoverview Shared utility functions.\n */\n\n/**\n * Formats a duration in seconds into a HH:MM:SS string.\n * @param seconds The duration in seconds.\n * @returns The formatted duration string.\n */\nexport const formatDuration = (seconds: number): string => {\n  if (isNaN(seconds) || seconds < 0) {\n    return '00:00:00'\n  }\n  const h = Math.floor(seconds / 3600)\n    .toString()\n    .padStart(2, '0')\n  const m = Math.floor((seconds % 3600) / 60)\n    .toString()\n    .padStart(2, '0')\n  const s = Math.floor(seconds % 60)\n    .toString()\n    .padStart(2, '0')\n  return `${h}:${m}:${s}`\n}\n",
            'tests/unit/socketManager.test.ts': "/**\n * @jest-environment node\n */\nimport {\n  afterAll,\n  afterEach,\n  beforeAll,\n  beforeEach,\n  describe,\n  expect,\n  it,\n  jest,\n} from '@jest/globals'\nimport {\n  initSocketManager,\n  resetSocketManager,\n} from '../../utils/socketManager'\nimport { Server as WebSocketServer } from 'ws'\nimport { EventEmitter } from 'events'\nimport { TLSSocket } from 'tls'\nimport TabataTimer from '../../services/tabataTimer'\nimport { SpotifyPolling } from '../../services/spotifyPolling'\nimport {\n  HrmData,\n  StateSnapshot,\n  ClientCommandMessageSchema,\n  ExtWebSocket,\n} from '../../types/websocket'\nimport {\n  broadcast,\n  sendWebSocketMessage,\n  ConnectionMonitor,\n} from '../../utils/websocketUtils.js'\nimport logger from '@/utils/logger'\nimport { createMockRequest } from './test-data/request-data-factory'\n\n// Mock dependencies\njest.mock('../../services/spotifyTokenManager')\njest.mock('@spotify/web-api-ts-sdk', () => ({\n  SpotifyApi: {\n    withAccessToken: jest.fn(),\n  },\n  AccessToken: jest.fn(),\n}))\n\n// Mock ConnectionMonitor and other utils\njest.mock('../../utils/websocketUtils.js', () => ({\n  sendWebSocketMessage: jest.fn(),\n  broadcast: jest.fn(),\n  ConnectionMonitor: jest.fn().mockImplementation(() => ({\n    start: jest.fn(),\n    stop: jest.fn(),\n  })),\n}))\n\n// Mock logger globally for the test file\njest.mock('../../utils/logger', () => ({\n  __esModule: true,\n  default: {\n    info: jest.fn(),\n    warn: jest.fn(),\n    error: jest.fn(),\n    debug: jest.fn(),\n  },\n}))\n\n// Manual mock for the 'ws' module\njest.mock('ws', () => ({\n  Server: jest.fn().mockImplementation(() => {\n    const wss = new EventEmitter() as jest.Mocked<WebSocketServer>\n    wss.clients = new Set<MockWebSocket>()\n    const originalOn = wss.on.bind(wss)\n    const originalEmit = wss.emit.bind(wss)\n    wss.on = jest.fn(\n      (event: string, listener: (...args: unknown[]) => void) => {\n        return originalOn(event, listener)\n      }\n    )\n    wss.emit = jest.fn((event: string, ...args: unknown[]) => {\n      return originalEmit(event, ...args)\n    })\n    return wss\n  }),\n  WebSocket: jest.fn(),\n}))\n\nclass MockWebSocket extends EventEmitter {\n  isAlive: boolean\n  clientType: string | undefined\n  clientId?: string\n  terminate = jest.fn()\n  ping = jest.fn()\n  send = jest.fn()\n\n  constructor() {\n    super()\n    this.isAlive = true\n  }\n\n  // Simulate receiving a pong from the client\n  receivePong() {\n    this.emit('pong')\n  }\n\n  // Override 'on' to correctly handle our event emitter\n  on(event: string | symbol, listener: (...args: unknown[]) => void): this {\n    super.on(event, listener)\n    return this\n  }\n}\n\ndescribe('WebSocket Manager', () => {\n  let mockWss: jest.Mocked<WebSocketServer>\n  let mockServices: {\n    tabataService: jest.Mocked<TabataTimer>\n    spotifyService: jest.Mocked<SpotifyPolling>\n  }\n  let getSnapshot: () => StateSnapshot\n  let mockWs: MockWebSocket\n\n  beforeEach(() => {\n    jest.useFakeTimers()\n    mockWss =\n      new (WebSocketServer as jest.Mock)() as jest.Mocked<WebSocketServer>\n\n    // Create fully typed mocks for the services.\n    const mockTabataTimer: jest.Mocked<TabataTimer> = {\n      handleCommand: jest.fn(),\n      setMode: jest.fn(),\n      setConfig: jest.fn(),\n      on: jest.fn(),\n      off: jest.fn(),\n      start: jest.fn(),\n      stop: jest.fn(),\n      pause: jest.fn(),\n      resume: jest.fn(),\n      getState: jest.fn(),\n      getSnapshot: jest.fn(),\n      cleanup: jest.fn(),\n    }\n\n    const mockSpotifyPolling: jest.Mocked<SpotifyPolling> = {\n      handleCommand: jest.fn(),\n      forcePollAndBroadcast: jest.fn(),\n      getState: jest.fn(),\n      isReady: jest.fn(),\n      handleTokenUpdate: jest.fn(),\n      startPolling: jest.fn(),\n      stopPolling: jest.fn(),\n      cleanup: jest.fn(),\n      refreshDevices: jest.fn(),\n    }\n\n    mockServices = {\n      tabataService: mockTabataTimer,\n      spotifyService: mockSpotifyPolling,\n    }\n\n    getSnapshot = jest.fn().mockReturnValue({\n      timer: {},\n      spotify: {},\n    })\n\n    initSocketManager(mockWss, getSnapshot, mockServices)\n    const mockReq = createMockRequest()\n    mockWs = new MockWebSocket()\n    ;(mockWss.clients as Set<MockWebSocket>).add(mockWs)\n    mockWss.emit('connection', mockWs, mockReq)\n  })\n\n  afterEach(() => {\n    jest.useRealTimers()\n    jest.clearAllMocks()\n    ;(mockWss.clients as Set<MockWebSocket>).clear()\n    resetSocketManager()\n  })\n\n  describe('Connection Logging', () => {\n    it('should log connection metadata on new connection', () => {\n      const loggerInfoSpy = jest.spyOn(logger, 'info')\n      const mockReq = createMockRequest('/?clientId=new-client-123')\n      const newWs = new MockWebSocket()\n\n      mockWss.emit('connection', newWs, mockReq)\n\n      expect(loggerInfoSpy).toHaveBeenCalledWith(\n        {\n          clientId: 'new-client-123',\n          ip: '127.0.0.1',\n          isSecure: false,\n          origin: 'http://localhost:3000',\n          userAgent: 'jest-test',\n          host: 'localhost:3000',\n        },\n        'WebSocket client connected'\n      )\n    })\n\n    it('should log a warning when overwriting an existing socket', () => {\n      const loggerWarnSpy = jest.spyOn(logger, 'warn')\n      const mockReq = createMockRequest('/?clientId=test-client') // Same clientId as in beforeEach\n      const newWs = new MockWebSocket()\n\n      mockWss.emit('connection', newWs, mockReq)\n\n      expect(loggerWarnSpy).toHaveBeenCalledWith(\n        {\n          clientId: 'test-client',\n          ip: '127.0.0.1',\n          isSecure: false,\n          origin: 'http://localhost:3000',\n          userAgent: 'jest-test',\n          host: 'localhost:3000',\n        },\n        'Existing socket found. Overwriting with new connection.'\n      )\n    })\n\n    it('should correctly identify a secure TLSSocket connection', () => {\n      const loggerInfoSpy = jest.spyOn(logger, 'info')\n      // Simulate a TLSSocket by creating an object with the correct prototype chain\n      const mockTlsSocket = Object.create(TLSSocket.prototype)\n      const mockReq = createMockRequest(\n        '/?clientId=secure-client',\n        {},\n        mockTlsSocket\n      )\n      const newWs = new MockWebSocket()\n\n      mockWss.emit('connection', newWs, mockReq)\n\n      expect(loggerInfoSpy).toHaveBeenCalledWith(\n        expect.objectContaining({\n          clientId: 'secure-client',\n          isSecure: true,\n        }),\n        'WebSocket client connected'\n      )\n    })\n\n    describe('Production Redaction', () => {\n      let originalNodeEnv: string | undefined\n\n      beforeAll(() => {\n        originalNodeEnv = process.env.NODE_ENV\n      })\n\n      afterAll(() => {\n        process.env.NODE_ENV = originalNodeEnv\n      })\n\n      it('should redact sensitive fields in production', async () => {\n        process.env.NODE_ENV = 'production'\n\n        const loggerInfoSpy = jest.spyOn(logger, 'info')\n        const mockReq = createMockRequest('/?clientId=prod-client')\n        const newWs = new MockWebSocket()\n\n        // Re-import the module to get the version with the updated process.env\n        await jest.isolateModulesAsync(async () => {\n          const { initSocketManager: initSocketManagerProd } =\n            await import('../../utils/socketManager')\n\n          // Use the re-imported init function\n          initSocketManagerProd(mockWss, getSnapshot, mockServices)\n          mockWss.emit('connection', newWs, mockReq)\n\n          expect(loggerInfoSpy).toHaveBeenCalledWith(\n            {\n              clientId: 'prod-client',\n              ip: '[REDACTED]',\n              isSecure: false,\n              origin: '[REDACTED]',\n              userAgent: '[REDACTED]',\n              host: 'localhost:3000',\n            },\n            'WebSocket client connected'\n          )\n        })\n      })\n    })\n  })\n\n  describe('Connection Monitoring', () => {\n    it('should initialize and start the ConnectionMonitor', () => {\n      expect(ConnectionMonitor).toHaveBeenCalledWith(mockWss)\n      const monitorInstance = (ConnectionMonitor as jest.Mock).mock.results[0]\n        .value\n      expect(monitorInstance.start).toHaveBeenCalled()\n    })\n\n    it('should set isAlive to true on new connection', () => {\n      const newWs = new MockWebSocket() as ExtWebSocket\n      const mockReq = createMockRequest()\n      mockWss.emit('connection', newWs, mockReq)\n      expect(newWs.isAlive).toBe(true)\n    })\n\n    it('should set isAlive to true on pong', () => {\n      const newWs = new MockWebSocket() as ExtWebSocket\n      const mockReq = createMockRequest()\n      mockWss.emit('connection', newWs, mockReq)\n      newWs.isAlive = false // Manually set to false\n      newWs.emit('pong')\n      expect(newWs.isAlive).toBe(true)\n    })\n\n    it('should stop the ConnectionMonitor when the server closes', () => {\n      mockWss.emit('close')\n      const monitorInstance = (ConnectionMonitor as jest.Mock).mock.results[0]\n        .value\n      expect(monitorInstance.stop).toHaveBeenCalled()\n    })\n\n    it('should set isAlive to true on any message', () => {\n      const newWs = new MockWebSocket() as ExtWebSocket\n      const mockReq = createMockRequest()\n      mockWss.emit('connection', newWs, mockReq)\n      newWs.isAlive = false // Manually set to false\n      const message = JSON.stringify({ type: 'PING' })\n      newWs.emit('message', message.toString())\n      expect(newWs.isAlive).toBe(true)\n    })\n  })\n\n  describe('Calorie Calculation', () => {\n    it('should accumulate calories correctly with small frequent updates', () => {\n      const sendHrmInput = (hr: number) => {\n        const message = JSON.stringify({\n          type: 'HRM_INPUT',\n          data: { value: hr, age: 30 },\n        })\n        mockWs.emit('message', message.toString())\n      }\n\n      // Initial input\n      sendHrmInput(150)\n\n      // Send 100 updates, each 100ms apart\n      // Should accumulate significant calories even if each step < 0.1 kcal\n      for (let i = 0; i < 100; i++) {\n        jest.advanceTimersByTime(100) // 100ms\n        sendHrmInput(150)\n      }\n\n      // Check the last broadcasted state\n      const mockBroadcast = broadcast as jest.Mock\n      jest.runOnlyPendingTimers()\n      expect(mockBroadcast).toHaveBeenCalled()\n      const lastCall =\n        mockBroadcast.mock.calls[mockBroadcast.mock.calls.length - 1]\n      const finalPayload: HrmData[] = lastCall[1].payload\n      const clientData = finalPayload.find((c) => c.calories > 0)\n\n      expect(clientData).toBeDefined()\n      expect(clientData!.calories).toBeGreaterThan(0.1)\n      // A more precise check based on the known formula for short duration.\n      // 100 updates * 100ms = 10 seconds = 0.1667 minutes.\n      // With HR=150, Age=30, Weight=75, the calories should be roughly > 1.\n      expect(clientData!.calories).toBeGreaterThan(1)\n    })\n\n    it('should reset calories when a STOP command is received', () => {\n      const sendHrmInput = (hr: number) => {\n        const message = JSON.stringify({\n          type: 'HRM_INPUT',\n          data: { value: hr, age: 30 },\n        })\n        mockWs.emit('message', message.toString())\n      }\n\n      // 1. Accumulate some calories\n      sendHrmInput(150)\n      jest.advanceTimersByTime(1000)\n      sendHrmInput(150)\n\n      // Verify calories have accumulated\n      const mockBroadcast = broadcast as jest.Mock\n      let lastCall =\n        mockBroadcast.mock.calls[mockBroadcast.mock.calls.length - 1]\n      let payload: HrmData[] = lastCall[1].payload\n      expect(payload[0].calories).toBeGreaterThan(0)\n\n      // 2. Send the STOP command\n      const stopMessage = JSON.stringify({\n        type: 'TIMER_COMMAND',\n        command: 'STOP',\n      })\n      mockWs.emit('message', stopMessage)\n\n      // 3. Verify calories are reset\n      expect(mockServices.tabataService.handleCommand).toHaveBeenCalledWith(\n        'STOP'\n      )\n      lastCall = mockBroadcast.mock.calls[mockBroadcast.mock.calls.length - 1]\n      payload = lastCall[1].payload\n      expect(payload[0].calories).toBeGreaterThan(0)\n    })\n  })\n\n  describe('Message Handling', () => {\n    it('should handle REGISTER_CLIENT message', () => {\n      const message = JSON.stringify({\n        type: 'REGISTER_CLIENT',\n        role: 'dashboard',\n      })\n      mockWs.emit('message', message.toString())\n      expect((mockWs as ExtWebSocket).clientType).toBe('dashboard')\n    })\n\n    it('should send initial state on GET_STATE message', () => {\n      const message = JSON.stringify({ type: 'GET_STATE' })\n      mockWs.emit('message', message.toString())\n\n      expect(getSnapshot).toHaveBeenCalled()\n      expect(sendWebSocketMessage).toHaveBeenCalled()\n      const sentData = (sendWebSocketMessage as jest.Mock).mock.calls[0][1]\n      expect(sentData.type).toBe('INITIAL_STATE')\n      expect(sentData.payload).toHaveProperty('timer')\n      expect(sentData.payload).toHaveProperty('spotify')\n      expect(sentData.payload).toHaveProperty('hrmData')\n    })\n\n    it('should handle invalid JSON gracefully', () => {\n      mockWs.emit('message', 'invalid json')\n      expect(logger.error).toHaveBeenCalledWith(\n        expect.objectContaining({ clientId: 'test-client' }),\n        'Error processing incoming message'\n      )\n    })\n\n    it('should handle Zod validation errors gracefully', () => {\n      const message = JSON.stringify({ type: 'INVALID_TYPE' })\n      mockWs.emit('message', message.toString())\n      expect(logger.error).toHaveBeenCalledWith(\n        expect.objectContaining({ clientId: 'test-client' }),\n        'WebSocket message validation failed'\n      )\n    })\n\n    it('should broadcast state on client disconnect', () => {\n      mockWs.emit('close')\n      jest.runAllTimers()\n      expect(broadcast).toHaveBeenCalledWith(\n        mockWss,\n        {\n          type: 'HRM_UPDATE',\n          payload: [],\n        },\n        'socketManager.broadcastState'\n      )\n    })\n\n    it('should forward SPOTIFY_COMMAND to dashboard clients', () => {\n      const dashboardWs = new MockWebSocket() as ExtWebSocket\n      dashboardWs.clientType = 'dashboard'\n      const controllerWs = new MockWebSocket() as ExtWebSocket\n      controllerWs.clientType = 'controller'\n      ;(mockWss.clients as Set<MockWebSocket>).add(dashboardWs)\n      ;(mockWss.clients as Set<MockWebSocket>).add(controllerWs)\n\n      const message = JSON.stringify({\n        type: 'SPOTIFY_COMMAND',\n        command: 'PLAY',\n      })\n      mockWs.emit('message', message.toString())\n\n      expect(sendWebSocketMessage).toHaveBeenCalled()\n      expect(sendWebSocketMessage).toHaveBeenCalledWith(\n        dashboardWs,\n        expect.objectContaining({ type: 'EXECUTE_SPOTIFY' }),\n        'socketManager.SPOTIFY_COMMAND'\n      )\n      expect(mockServices.spotifyService.handleCommand).toHaveBeenCalledWith(\n        'PLAY',\n        {}\n      )\n    })\n\n    it('should extract contextUri and playlistUri from SPOTIFY_COMMAND', () => {\n      const message = JSON.stringify({\n        type: 'SPOTIFY_COMMAND',\n        command: 'PLAY',\n        deviceId: 'test_device',\n        volume: 50,\n        playlistUri: 'spotify:playlist:123',\n        contextUri: 'spotify:album:456',\n      })\n      mockWs.emit('message', message.toString())\n\n      expect(mockServices.spotifyService.handleCommand).toHaveBeenCalledWith(\n        'PLAY',\n        {\n          deviceId: 'test_device',\n          volume: 50,\n          playlistUri: 'spotify:playlist:123',\n          contextUri: 'spotify:album:456',\n        }\n      )\n    })\n\n    it('should extract uri from SPOTIFY_COMMAND', () => {\n      const message = JSON.stringify({\n        type: 'SPOTIFY_COMMAND',\n        command: 'PLAY',\n        deviceId: 'test_device',\n        uri: 'spotify:track:12345',\n      })\n      mockWs.emit('message', message.toString())\n\n      expect(mockServices.spotifyService.handleCommand).toHaveBeenCalledWith(\n        'PLAY',\n        {\n          deviceId: 'test_device',\n          uri: 'spotify:track:12345',\n        }\n      )\n    })\n\n    it('should handle unknown message types', () => {\n      const message = JSON.stringify({ type: 'SOME_GARBAGE' })\n      jest\n        .spyOn(ClientCommandMessageSchema, 'parse')\n        .mockReturnValue({ type: 'SOME_GARBAGE' } as unknown)\n\n      mockWs.emit('message', message.toString())\n\n      expect(logger.warn).toHaveBeenCalledWith(\n        expect.objectContaining({ clientId: 'test-client' }),\n        'Unknown message type received'\n      )\n    })\n  })\n})\n",
            'utils/socketManager.ts': '// File: utils/socketManager.ts (WebSocket Manager - Typed)\n/**\n * WebSocket Manager (Typed): Handles client connections, routes commands, and broadcasts state.\n */\nimport { WebSocket, Server as WebSocketServer } from \'ws\'\nimport { z } from \'zod\' // Import z from zod\nimport { IncomingMessage } from \'http\'\nimport { TLSSocket } from \'tls\'\nimport {\n  ClientCommandMessageSchema,\n  ClientRegistrationMessage,\n  SpotifyCommandMessage,\n  SpotifyExecutionMessage,\n  InitialStateSnapshotPayload,\n  ServerMessage,\n  StateSnapshot,\n  ExtWebSocket,\n} from \'../types/websocket.js\'\nimport { HrmStreamData } from \'../types/core.js\'\nimport { CALORIE_DEFAULTS } from \'./constants.js\' // Ensure this import exists\nimport {\n  broadcast,\n  sendWebSocketMessage,\n  ConnectionMonitor,\n} from \'./websocketUtils.js\'\nimport logger from \'./logger.js\'\nimport { estimateCaloriesBurned } from \'../lib/calorie-estimation.js\'\nimport { HrmDataRepository } from \'../lib/repositories/HrmDataRepository.js\'\nimport { AppServices } from \'../lib/services.js\'\nimport { env } from \'../lib/env.js\'\n\n// Define service instances to be managed\n// New: Define a function to get the state snapshot\nlet getUnifiedStateSnapshot: () => StateSnapshot\n// Store WebSocket server reference for command relay\nlet wsServerInstance: WebSocketServer\nlet connectionMonitor: ConnectionMonitor\nlet services: AppServices\n\n// State Management:\n// - hrmDataRepository: Stores the live HRM data for each client (e.g., HR value, calories). This is the primary source of truth for broadcasted state.\n// - clientSockets: Maps a clientId to their active WebSocket connection. Used to handle zombie connections and check for reconnections.\n// - clientSessionState: Holds internal server state for calculations (e.g., calorie accumulation), not sent to the client.\nconst hrmDataRepository = new HrmDataRepository()\n\n// Track active sockets separately so we can handle "zombie" sockets during reconnects\nconst clientSockets = new Map<string, WebSocket>()\n\n// Track internal state for calculations (not sent to client)\nconst clientSessionState = new Map<\n  string,\n  { lastUpdate: number; accumulatedCalories: number }\n>()\n\n/**\n * Safely parses the WebSocket request URL to extract search parameters.\n * Handles cases where headers or URL might be malformed.\n * @param req - The incoming HTTP request from the WebSocket upgrade.\n * @returns URLSearchParams object, which will be empty if parsing fails.\n */\nconst getRequestParams = (req: IncomingMessage): URLSearchParams => {\n  try {\n    // Fallback to localhost if host header is missing, which can happen in some proxy/test setups\n    const host = req.headers.host || \'localhost\'\n    const protocol = \'http\' // WebSocket upgrades start as HTTP\n    const url = new URL(req.url || \'/\', `${protocol}://${host}`)\n    return url.searchParams\n  } catch (error) {\n    logger.error({ error }, \'Failed to parse WebSocket connection URL\')\n    // Return empty params to prevent a crash on invalid URL\n    return new URLSearchParams()\n  }\n}\n\n/**\n * Creates a metadata object for logging, with sensitive data redaction in production.\n * @param req - The incoming HTTP request.\n * @param clientId - The client\'s identifier.\n * @returns An object with connection details for logging.\n */\nconst getLogMeta = (\n  req: IncomingMessage,\n  clientId: string\n): Record<string, unknown> => {\n  // DEV-NOTE: Be mindful of logging sensitive data. In a real-world scenario,\n  // IP addresses and user-agents might be considered PII and should be\n  // handled according to privacy policies. Redacting in production is a safeguard.\n  const isProduction = process.env.NODE_ENV === \'production\'\n\n  const ip = req.socket.remoteAddress\n  const userAgent = req.headers[\'user-agent\']\n  const origin = req.headers.origin\n\n  return {\n    clientId,\n    ip: isProduction ? \'[REDACTED]\' : ip,\n    isSecure: req.socket instanceof TLSSocket,\n    origin: isProduction ? \'[REDACTED]\' : origin,\n    userAgent: isProduction ? \'[REDACTED]\' : userAgent,\n    host: req.headers.host || \'[UNKNOWN]\',\n  }\n}\n\n/**\n * Initializes the WebSocket Server manager and registers the core services.\n */\nconst initSocketManager = (\n  wss: WebSocketServer,\n  getSnapshot: () => StateSnapshot,\n  svcs: AppServices\n) => {\n  wsServerInstance = wss\n  getUnifiedStateSnapshot = getSnapshot\n  services = svcs\n  connectionMonitor = new ConnectionMonitor(wss)\n  connectionMonitor.start()\n\n  wss.on(\'connection\', (ws: WebSocket, req: IncomingMessage) => {\n    const extWs = ws as ExtWebSocket\n\n    const params = getRequestParams(req)\n    const clientId =\n      params.get(\'clientId\') ||\n      `[GENERATED]-user-${Math.random().toString(36).substring(2, 9)}`\n    const logMeta = getLogMeta(req, clientId)\n    extWs.clientId = clientId\n\n    // it\'s a stale or "zombie" connection. Overwrite it with the new socket.\n\n    if (clientSockets.has(clientId)) {\n      logger.warn(\n        logMeta,\n        \'Existing socket found. Overwriting with new connection.\'\n      )\n    }\n\n    clientSockets.set(clientId, extWs)\n\n    extWs.isAlive = true\n    extWs.on(\'pong\', () => {\n      extWs.isAlive = true\n    })\n\n    logger.info(logMeta, \'WebSocket client connected\')\n\n    if (!hrmDataRepository.findById(clientId)) {\n      // Initialize new client\n      const newClient: HrmStreamData = {\n        clientId: extWs.clientId,\n        value: 0,\n        maxHr: 185,\n        age: 30,\n        calories: 0, // Initialize to 0\n      }\n      hrmDataRepository.save(newClient)\n      clientSessionState.set(extWs.clientId, {\n        lastUpdate: Date.now(),\n        accumulatedCalories: 0,\n      })\n    } else {\n      logger.info({ clientId }, \'Reconnected with existing session.\')\n    }\n\n    extWs.on(\'message\', (message) => {\n      handleIncomingMessage(extWs, message.toString(), extWs.clientId)\n    })\n\n    extWs.on(\'close\', () => {\n      logger.info({ clientId: extWs.clientId }, \'WebSocket client disconnected\')\n\n      // CRITICAL: Do NOT immediately delete clientData.\n      // Wait a grace period (e.g., 5 seconds) to allow for page refresh.\n      // NOTE: In a high-traffic production environment, this could lead to\n      // memory pressure if many clients disconnect and don\'t reconnect.\n      // A more robust solution might involve a separate cleanup process\n      // or a maximum number of inactive sessions.\n      setTimeout(() => {\n        // Only delete if they haven\'t reconnected (i.e., the current socket is still this closed one)\n        if (clientSockets.get(clientId) === extWs) {\n          logger.info(\n            { clientId: extWs.clientId },\n            \'Session expired. Deleting data.\'\n          )\n          try {\n            hrmDataRepository.deleteById(extWs.clientId)\n            clientSessionState.delete(extWs.clientId)\n            broadcastState()\n          } catch (err) {\n            logger.error(\n              { clientId: extWs.clientId, error: err },\n              \'Error during session cleanup\'\n            )\n          } finally {\n            // Always remove the socket reference to prevent leaks\n            clientSockets.delete(extWs.clientId)\n          }\n        }\n      }, env.WEBSOCKET_GRACE_PERIOD_MS)\n    })\n  })\n\n  wss.on(\'close\', () => {\n    connectionMonitor.stop()\n  })\n}\n\n/**\n * Resets the socket manager state. Use this for testing purposes only.\n */\nexport const resetSocketManager = () => {\n  hrmDataRepository.clear()\n  clientSessionState.clear()\n}\n\nconst broadcastState = () => {\n  broadcast(\n    wsServerInstance,\n    {\n      type: \'HRM_UPDATE\',\n      payload: hrmDataRepository.findAll(),\n    },\n    \'socketManager.broadcastState\'\n  )\n}\n\n/**\n * Handles incoming JSON messages from client applications.\n */\nconst handleIncomingMessage = (\n  ws: ExtWebSocket,\n  messageString: string,\n  clientId: string\n) => {\n  // Any message from the client indicates they are still alive.\n  ws.isAlive = true\n  try {\n    const parsedJson = JSON.parse(messageString)\n    const message = ClientCommandMessageSchema.parse(parsedJson)\n\n    switch (message.type) {\n      case \'PING\': {\n        // Respond to client heartbeat pings to keep the connection alive\n        logger.info({ clientId }, \'Received PING, sending PONG.\')\n        const pongMessage: ServerMessage = { type: \'PONG\' }\n        sendWebSocketMessage(ws, pongMessage, \'socketManager.PING\')\n        break\n      }\n      case \'REGISTER_CLIENT\': {\n        ws.clientType = (message as ClientRegistrationMessage).role\n        logger.info(\n          { clientId, clientType: ws.clientType },\n          \'Client registered\'\n        )\n        break\n      }\n      case \'GET_STATE\': {\n        const stateSnapshot = getUnifiedStateSnapshot()\n        const payload: InitialStateSnapshotPayload = {\n          ...stateSnapshot,\n          hrmData: hrmDataRepository.findAll(),\n        }\n        const initialStateMessage: ServerMessage = {\n          type: \'INITIAL_STATE\',\n          payload: payload,\n        }\n        sendWebSocketMessage(ws, initialStateMessage, \'socketManager.GET_STATE\')\n        break\n      }\n      case \'HRM_METADATA_UPDATE\': {\n        const existingData = hrmDataRepository.findById(clientId)\n        if (existingData) {\n          const updateData: Partial<HrmStreamData> = Object.fromEntries(\n            Object.entries(message.data).filter(([_, value]) => value !== null)\n          )\n\n          // Prevent overwriting a real name with a default "Unknown" name\n          if (\n            existingData.name &&\n            !/^(user|new user|unknown|bluetooth hrm)/i.test(\n              existingData.name\n            ) &&\n            updateData.name &&\n            /^(user|new user|unknown|bluetooth hrm)/i.test(updateData.name)\n          ) {\n            delete updateData.name\n          }\n\n          hrmDataRepository.save({ ...existingData, ...updateData })\n        }\n        broadcastState()\n        break\n      }\n      case \'HRM_INPUT\': {\n        const existingData = hrmDataRepository.findById(clientId)\n        const sessionState = clientSessionState.get(clientId)\n        if (existingData && sessionState) {\n          let finalCalories = 0\n          // Prioritize client-calculated calories if available\n          if (typeof message.data.calories === \'number\') {\n            const clientCalories = message.data.calories\n            const serverCalories = sessionState.accumulatedCalories\n            const diff = Math.abs(clientCalories - serverCalories)\n\n            // Sanity check: a 50-calorie jump in one second is unlikely.\n            if (diff > 50) {\n              logger.warn(\n                {\n                  clientId,\n                  clientCalories,\n                  serverCalories,\n                },\n                \'Large calorie discrepancy detected. Rejecting client update.\'\n              )\n              finalCalories = serverCalories\n            } else {\n              finalCalories = clientCalories\n              sessionState.accumulatedCalories = finalCalories\n            }\n          } else {\n            // Fallback to server-side calculation for older clients\n            const now = Date.now()\n            const dtMinutes = (now - sessionState.lastUpdate) / 1000 / 60\n            sessionState.lastUpdate = now\n\n            let currentAccumulated = sessionState.accumulatedCalories\n            const currentHr = message.data.value ?? existingData.value\n            const currentAge = existingData.age ?? 30\n            if (currentHr > 30 && dtMinutes > 0 && dtMinutes < 5) {\n              const caloriesBurned = estimateCaloriesBurned({\n                heartRate: currentHr,\n                age: currentAge,\n                weightKg: existingData.weightKg ?? CALORIE_DEFAULTS.WEIGHT_KG,\n                durationMinutes: dtMinutes,\n              })\n              currentAccumulated += caloriesBurned\n            }\n            sessionState.accumulatedCalories = currentAccumulated\n            finalCalories = currentAccumulated\n          }\n          // Update the repository with the latest data\n          hrmDataRepository.save({\n            ...existingData,\n            value: message.data.value ?? existingData.value,\n            calories: Math.round(finalCalories * 10) / 10,\n          })\n        }\n        broadcastState()\n        break\n      }\n\n      case \'TIMER_COMMAND\':\n        services.tabataService.handleCommand(message.command)\n        break\n\n      case \'SET_MODE\':\n        services.tabataService.setMode(message.mode)\n        break\n\n      case \'TIMER_CONFIG\':\n        services.tabataService.setConfig({\n          workDuration: message.workDuration,\n          restDuration: message.restDuration,\n        })\n        break\n\n      case \'SPOTIFY_COMMAND\': {\n        const commandMsg = message as SpotifyCommandMessage\n        logger.info(\n          { clientId, command: commandMsg.command },\n          \'Forwarding Spotify command\'\n        )\n\n        wsServerInstance.clients.forEach((client: WebSocket) => {\n          const target = client as ExtWebSocket\n          if (\n            target.readyState === WebSocket.OPEN &&\n            target.clientType === \'dashboard\'\n          ) {\n            const executionMessage: SpotifyExecutionMessage = {\n              type: \'EXECUTE_SPOTIFY\',\n              payload: commandMsg,\n            }\n            sendWebSocketMessage(\n              target,\n              executionMessage,\n              \'socketManager.SPOTIFY_COMMAND\'\n            )\n          }\n        })\n\n        const spotifyService = services.spotifyService\n        const spotifyCommandParams: {\n          deviceId?: string\n          volume?: number\n          playlistUri?: string\n          contextUri?: string\n          uri?: string\n        } = {}\n        if (commandMsg.deviceId)\n          spotifyCommandParams.deviceId = commandMsg.deviceId\n        if (commandMsg.volume !== undefined)\n          spotifyCommandParams.volume = commandMsg.volume\n        if (commandMsg.playlistUri)\n          spotifyCommandParams.playlistUri = commandMsg.playlistUri\n        if (commandMsg.contextUri)\n          spotifyCommandParams.contextUri = commandMsg.contextUri\n        if (commandMsg.uri) spotifyCommandParams.uri = commandMsg.uri\n\n        spotifyService.handleCommand(commandMsg.command, spotifyCommandParams)\n        break\n      }\n      default: {\n        const unknownMessage = message as { type: unknown }\n        logger.warn(\n          { clientId, type: unknownMessage.type },\n          \'Unknown message type received\'\n        )\n        break\n      }\n    }\n  } catch (e) {\n    if (e instanceof z.ZodError) {\n      logger.error(\n        { clientId, errors: e.issues },\n        \'WebSocket message validation failed\'\n      )\n    } else {\n      logger.error({ clientId, error: e }, \'Error processing incoming message\')\n    }\n  }\n}\n\nexport { initSocketManager, getRequestParams }\n',
        }
